// src/components/Home.js
import React, { useState, useEffect } from "react";
import axios from "axios"; // Импортируем axios для запросов (имитация запроса)
import TreeView from "react-treeview"; // Импортируем TreeView для отображения дерева
import "./Home.css"; // Импортируем CSS файл

const Home = () => {
    const [directories, setDirectories] = useState([]); // Структура директорий
    const [selectedDir, setSelectedDir] = useState(null); // Выбранная директория
    const [selectedFile, setSelectedFile] = useState(null); // Выбранный файл

    // Имитация асинхронного запроса для получения данных о структурах директорий и файлов
    useEffect(() => {
        // Имитация запроса
        const fetchDirectories = () => {
            // Данные, которые обычно приходят с бэкенда
            const simulatedData = [
                {
                    name: "Documents",
                    subdirectories: [
                        {
                            name: "Work",
                            files: ["report.docx", "budget.xlsx"],
                        },
                        {
                            name: "Personal",
                            files: ["letter.txt", "cv.pdf"],
                        },
                    ],
                },
                {
                    name: "Downloads",
                    subdirectories: [
                        {
                            name: "Images",
                            files: ["photo1.jpg", "photo2.png"],
                        },
                        {
                            name: "Videos",
                            files: ["video1.mp4", "video2.mkv"],
                        },
                    ],
                },
            ];

            // Имитация задержки запроса
            setTimeout(() => {
                setDirectories(simulatedData); // Сохраняем имитированные данные в состояние
            }, 1000); // Задержка 1 секунда
        };

        fetchDirectories(); // Вызываем имитацию получения данных
    }, []); // Пустой массив зависимостей, чтобы запрос выполнялся только один раз при монтировании

    // Обработчик выбора директории
    const handleDirectorySelect = (dir) => {
        setSelectedDir(dir); // Устанавливаем выбранную директорию
        setSelectedFile(null); // Сбрасываем выбранный файл
    };

    // Обработчик выбора файла
    const handleFileSelect = (file) => {
        setSelectedFile(file); // Устанавливаем выбранный файл
    };

    // Рекурсивная функция для рендеринга дерева директорий
    const renderTree = (dir) => (
        <TreeView
            key={dir.name}
            nodeLabel={dir.name}
            collapsed={false}
            render={renderCustomTreeNode}
        >
            {dir.subdirectories.map((subDir) => (
                <div key={subDir.name}>
                    <TreeView
                        nodeLabel={subDir.name}
                        collapsed={false}
                        render={renderCustomTreeNode}
                    >
                        {subDir.files.map((file) => (
                            <div key={file}>
                                <button
                                    className="button"
                                    onClick={() => handleFileSelect(file)}
                                >
                                    {file}
                                </button>
                            </div>
                        ))}
                    </TreeView>
                </div>
            ))}
        </TreeView>
    );

    // Функция для кастомного рендеринга узла
    const renderCustomTreeNode = (state) => {
        return (
            <div className="tree-node">
                <span>{state.nodeLabel}</span>
            </div>
        );
    };

    return (
        <div className="container">
            <div className="content-wrapper">
                {/* Боковой раздел */}
                <div className="sidebar">
                    <h3>Директории</h3>
                    {directories.length === 0 ? (
                        <p>Загрузка директорий...</p> // Показать текст, пока идет загрузка
                    ) : (
                        directories.map((dir) => (
                            <div key={dir.name}>
                                <button
                                    className="button"
                                    onClick={() => handleDirectorySelect(dir)}
                                >
                                    {dir.name}
                                </button>
                                {selectedDir === dir && renderTree(dir)}{" "}
                                {/* Рендерим дерево для выбранной директории */}
                            </div>
                        ))
                    )}
                </div>

                {/* Основной раздел */}
                <div className="mainContent">
                    {selectedDir ? (
                        <>
                            <h3>Файлы в {selectedDir.name}</h3>
                            <ul className="fileList">
                                {selectedDir.subdirectories.map(
                                    (subDir, idx) => (
                                        <div key={idx}>
                                            <h4>{subDir.name}</h4>
                                            <ul>
                                                {subDir.files.map(
                                                    (file, fileIdx) => (
                                                        <li key={fileIdx}>
                                                            <button
                                                                className="button"
                                                                onClick={() =>
                                                                    handleFileSelect(
                                                                        file
                                                                    )
                                                                }
                                                            >
                                                                {file}
                                                            </button>
                                                        </li>
                                                    )
                                                )}
                                            </ul>
                                        </div>
                                    )
                                )}
                            </ul>
                        </>
                    ) : (
                        <p>Выберите директорию для отображения файлов.</p>
                    )}
                </div>
            </div>

            {/* Нижний раздел */}
            <div className="footer">
                {selectedFile ? (
                    <div>
                        <h4>Содержимое файла: {selectedFile}</h4>
                        <p>Здесь будет отображаться содержимое файла...</p>
                    </div>
                ) : (
                    <p>Выберите файл для просмотра содержимого.</p>
                )}
            </div>
        </div>
    );
};

export default Home;
